#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

kernel void bpnn_layerforward_ocl(global float* l1,
                                  global float* l2,
                                  global float* conn_flat,
                                  global float* partial_sum,
                                  local float* local_conn,
                                  local float* local_l1,
                                  int n1,
                                  int n2) {
    int j = get_global_id(1);
    int k_block = get_global_id(0);

    if (j >= n2 || j < 1) return;

    int block_size = BLOCK_SIZE;
    int k_start = k_block * block_size;

    float sum = 0.0f;

    for (int k_local = 0; k_local < block_size; k_local++) {
        int k = k_start + k_local;
        if (k <= n1) {
            float weight = conn_flat[k * (n2 + 1) + j];
            float input_val = (k == 0) ? 1.0f : l1[k];
            sum += weight * input_val;
        }
    }

    partial_sum[k_block * n2 + (j - 1)] = sum;
}

kernel void bpnn_adjust_weights_ocl(global float* delta,
                                    int ndelta,
                                    global float* ly,
                                    int nly,
                                    global float* w_flat,
                                    global float* oldw_flat) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j < 1 || j > ndelta) return;
    if (k > nly) return;

    float ly_val = (k == 0) ? 1.0f : ly[k];
    float delta_val = delta[j];

    int idx = k * (ndelta + 1) + j;
    float old_dw = oldw_flat[idx];
    float new_dw = (ETA * delta_val * ly_val) + (MOMENTUM * old_dw);

    w_flat[idx] += new_dw;
    oldw_flat[idx] = new_dw;
}
